// Parse romaneio PDF text
const text = $json.data || $json.text || '';
const fileName = $json.fileName || $input.first().json.fileName || '';

function ct(v) { return String(v == null ? '' : v).replace(/\s+/g,' ').trim(); }
function parseNum(v) {
  if (!v) return 0;
  var s = ct(v).replace(/\./g,'').replace(',','.');
  var n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

// Extract ORDEM DE CARGA
var ordemMatch = text.match(/ORDEM\s+DE\s+CARGA[:\s]+(\d+)/i);
var ordemCarga = ordemMatch ? ordemMatch[1] : '';

// Extract EMPRESA
var empresaMatch = text.match(/EMPRESA[:\s]+(\d+)\s*-\s*(.+?)(?:\n|$)/i);
var codigoEmpresa = empresaMatch ? ct(empresaMatch[1]) : '';
var nomeEmpresa = empresaMatch ? ct(empresaMatch[2]) : '';

if (!ordemCarga) {
  // Try from filename: ROMANEIO 565.pdf
  var fnMatch = fileName.match(/ROMANEIO\s+(\d+)/i);
  if (fnMatch) ordemCarga = fnMatch[1];
}

// Parse PEDIDOS section
var pedidos = [];
var pedidosSection = text.split(/PEDIDOS/i)[1] || '';
pedidosSection = pedidosSection.split(/ITENS\s+DO\s+CAMINHA/i)[0] || pedidosSection;
pedidosSection = pedidosSection.split(/MONTANTE/i)[0] || pedidosSection;

var pedidoLines = pedidosSection.split('\n');
for (var line of pedidoLines) {
  var l = ct(line);
  if (!l) continue;
  // Pattern: NUNICO PEDMERCOS CODPARCEIRO - NOME PARCEIRO CIDADE VALOR
  var m = l.match(/^(\d+)\s+(\d+)\s+(\d+)\s*-\s*(.+?)\s{2,}(\S.*?)\s+([\d.,]+)$/);
  if (m) {
    pedidos.push({
      numero_unico: m[1],
      ped_mercos: m[2],
      codigo_parceiro: m[3],
      nome_parceiro: ct(m[4]),
      cidade: ct(m[5]),
      valor_total: parseNum(m[6])
    });
  }
}

// Extract MONTANTE
var montanteMatch = text.match(/MONTANTE[:\s]+(\d+)/i);
var montante = montanteMatch ? Number(montanteMatch[1]) : pedidos.length;

// Extract total value after MONTANTE
var totalGeralMatch = text.match(/MONTANTE[:\s]+\d+\s+([\d.,]+)/i);
var totalGeral = totalGeralMatch ? parseNum(totalGeralMatch[1]) : 0;

// Parse ITENS DO CAMINHAO section
var itens = [];
var itensSection = text.split(/ITENS\s+DO\s+CAMINHA/i)[1] || '';
itensSection = itensSection.split(/TOTAL\s*:/i)[0] || itensSection;

// Skip header line (PRODUTO UND. QTD NEG. QTD VOL.)
var itensLines = itensSection.split('\n');
var headerFound = false;
for (var line of itensLines) {
  var l = ct(line);
  if (!l) continue;
  if (l.match(/PRODUTO/i) && l.match(/UND/i)) { headerFound = true; continue; }
  if (!headerFound) continue;

  // Pattern: SKU - DESCRICAO    UND    QTD_NEG    QTD_VOL (optional)
  var m = l.match(/^(\d+)\s*-\s*(.+?)\s{2,}(\S+)\s+([\d.,]+)(?:\s+([\d.,]+))?$/);
  if (m) {
    itens.push({
      sku: ct(m[1]),
      descricao: ct(m[2]),
      produto: ct(m[1]) + ' - ' + ct(m[2]),
      unidade: ct(m[3]),
      tipo_produto: 'PRODUTO ACABADO',
      quantidade: parseNum(m[4]),
      quantidade_neg: parseNum(m[4]),
      quantidade_vol: parseNum(m[5] || '0'),
      quantity_total: parseNum(m[4])
    });
  }
}

var now = new Date().toISOString();
function hsh(t) { var h=0; for(var i=0;i<t.length;i++){h=((h<<5)-h)+t.charCodeAt(i);h|=0;} return Math.abs(h).toString(16); }
var fp = JSON.stringify({oc:ordemCarga,ic:itens.length});
var eid = 'romaneio_pdf:' + ordemCarga + ':' + now.replace(/[:\-]/g,'').replace('.000Z','Z') + ':' + hsh(fp);

return {
  json: {
    source_code: 'romaneio_pdf',
    workflow_name: 'PCP | 15B | PDF Romaneio Ingest',
    payload: {
      event_id: eid,
      event_type: 'update',
      event_at: now,
      romaneio: {
        codigo: ordemCarga,
        empresa: codigoEmpresa,
        status: '1',
        pedido: pedidos.map(function(p){ return p.numero_unico; }).join(','),
        parceiro: pedidos.length ? pedidos[0].nome_parceiro : '',
        cidade: pedidos.length ? pedidos[0].cidade : '',
        valor_total: totalGeral || pedidos.reduce(function(s,p){ return s + p.valor_total; }, 0),
        itens: itens
      }
    },
    meta: {
      polling: false,
      native_n8n: true,
      source: 'pdf_parser',
      workflow_name: 'PCP | 15B | PDF Romaneio Ingest',
      file_name: fileName,
      items_source: itens.length ? 'pdf_itens_caminhao' : 'none',
      items_count: itens.length,
      pedidos_count: pedidos.length,
      montante: montante,
      total_geral: totalGeral,
      nome_empresa: nomeEmpresa,
      codigo_empresa: codigoEmpresa,
      ordem_carga: ordemCarga,
      pedidos_detail: pedidos,
      text_length: text.length,
      text_preview: text.substring(0, 500)
    }
  }
};

var esc = function(value) {
  var raw = JSON.stringify(value == null ? {} : value);
  return raw.replace(/\\/g, '\\\\').replace(/'/g, "''");
};
var escT = function(v) { return String(v == null ? '' : v).replace(/\\/g, '\\\\').replace(/'/g, "''"); };
var rom = ($json.payload || {}).romaneio || {};
var eid = escT(($json.payload || {}).event_id || '');
var rc = escT(rom.codigo || '');
var ic = Array.isArray(rom.itens) ? rom.itens.length : 0;
var sql = "select jsonb_build_object(\n"
  + "  'event_id','" + eid + "',\n"
  + "  'romaneio_code','" + rc + "',\n"
  + "  'item_count'," + ic + ",\n"
  + "  'ingest', ops.ingest_romaneio_event_payload(\n"
  + "    '" + escT($json.source_code || 'romaneio_pdf') + "',\n"
  + "    '" + esc($json.payload) + "'::jsonb,\n"
  + "    '" + esc($json.meta) + "'::jsonb\n"
  + "  )\n) as result;";
return { json: { ...$json, sql_query: sql } };

var row = $json || {};
var result = row.result != null ? row.result : row;
if (typeof result === 'string') { try { result = JSON.parse(result); } catch(e) { result = {status:'unknown'}; } }
var ingest = result.ingest || {};
return { json: {
  ok: ['processed','duplicate_ignored','noop'].indexOf(ingest.status || result.status) >= 0,
  workflow: 'PCP | 15B | PDF Romaneio Ingest',
  mode: 'pdf_parser', ...result, ingest: ingest
}};
